Greedy randomized adaptive search: evaluate feasible insertions across existing assigns and empty seeds using cheapest marginal cost selection per order.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for shipIdx := range oris {
		bestAssignIdx := -1
		bestDelta := 1e18
		orderId := total_ship + shipIdx
		ori := oris[shipIdx]
		des := dess[shipIdx]

		saveStates := make([]struct {
			station Station
			cost    float64
		}, dispatch.AssignsLen)

		for i := 0; i < dispatch.AssignsLen; i++ {
			assign := &dispatch.Assigns[i]
			saveStates[i].station = assign.StationCurrent
			saveStates[i].cost = assign.Cost

			if assign.AddShip(orderId, ori, des) {
				assign.GenRoute()
				newCost := assign.Cost
				delta := newCost - saveStates[i].cost
				if delta >= 0 && delta < bestDelta {
					bestDelta = delta
					bestAssignIdx = i
				}
			}
			assign.RemoveShip(orderId)
			assign.GenRoute()
		}

		fallbackIdx := -1
		if bestAssignIdx == -1 {
			start := dispatch.AssignsLen
			end := MAXASSIGNS
			if start >= end {
				panic("no available assign slot for fallback")
			}
			for i := start; i < end; i++ {
				if dispatch.Assigns[i].AddShip(orderId, ori, des) {
					dispatch.Assigns[i].GenRoute()
					bestAssignIdx = i
					dispatch.AssignsLen++
					break
				}
			}
			fallbackIdx = bestAssignIdx
		}

		if bestAssignIdx != -1 && fallbackIdx == -1 {
			dispatch.Assigns[bestAssignIdx].AddShip(orderId, ori, des)
			dispatch.Assigns[bestAssignIdx].GenRoute()
		}

		if bestAssignIdx == -1 {
			panic("order could not be inserted anywhere")
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

