func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	var rand_range [MAXASSIGNS]int
	var rand_limit int = 0 //记录有多少个有车的assign

	logger := zap.L().Named("Insert")

	// 生成随机序列 TODO: 有些车在时间触发过程中可能变空了
	for ii := range rand_range {
		rand_range[ii] = ii
		// 交换不空的解
		if ii < dispatch.AssignsLen && dispatch.Assigns[ii].StationsLen > 0 {
			rand_range[ii], rand_range[rand_limit] = rand_range[rand_limit], ii
			// 记录有多少个不空的解
			rand_limit += 1
		}
	}
	//由于不空的解都在前面，所以只需要打乱前面这部分
	rand.Shuffle(rand_limit, func(i, j int) {
		rand_range[i], rand_range[j] = rand_range[j], rand_range[i]
	})

	// 开始插入
	for jj := range oris {
		for _, ii := range rand_range {
			//尝试插入解
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {

				dispatch.Assigns[ii].Cost = -1

			} else {
				dispatch.Assigns[ii].GenRoute()

			}
			//插入失败
			if dispatch.Assigns[ii].Cost < 0 {
				//fmt.Println("inserted but not avaliable")
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			} else {
				//如果插入成功，并且插入了一辆空车，那么扩展一辆车
				if ii >= dispatch.AssignsLen {
					dispatch.AssignsLen += 1
				}
				break
			}
			// 应当一定有一辆车能插入成功,否则第assignslen也插入失败的话，说明该订单插不进去
			if ii >= dispatch.AssignsLen {
				logger.Warn(
					"Cannot Insert",
					zap.Int("ship", total_ship+jj),
					zap.Int("non_empty", rand_limit),
					zap.Int("assigns_len", dispatch.AssignsLen),
				)
				fmt.Println(oris[jj], dess[jj])
				dispatch.Assigns[dispatch.AssignsLen].PrettyPrint()
				//dispatch.Assigns[dispatch.AssignsLen].AddShip(total_ship + jj, oris[jj], dess[jj])
				//checkDispatch(&dispatch)
				break
			}
		}
	}
	dispatch.RenewnTotalCost()
	//XXX: 调查发现,insertion不会改变累计里程，是别的东西删除了累计里程
	return dispatch
}

algorithm:
My algorithm evaluates each order against all existing assigns using trial insertion with cost comparison, selects the best feasible assign per order based on incremental cost increase, and falls back to a new empty assign if no existing assign accepts the order.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	for jj := 0; jj < orderCount; jj++ {
		bestIdx := -1
		minDelta := 1e100
		ori := oris[jj]
		des := dess[jj]
		shipID := total_ship + jj
		// Try each existing assign
		for idx := 0; idx < dispatch.AssignsLen; idx++ {
			assign := &dispatch.Assigns[idx]
			oldCost := assign.Cost
			// Trial insert
			if !assign.AddShip(shipID, ori, des) {
				continue
			}
			assign.GenRoute()
			newCost := assign.Cost
			delta := newCost - oldCost
			if newCost >= 0 && delta < minDelta {
				minDelta = delta
				bestIdx = idx
			}
			// Rollback
			assign.RemoveShip(shipID)
			assign.GenRoute()
		}
		// Also try a potential new assign (next unused slot)
		potentialNewIdx := dispatch.AssignsLen
		if potentialNewIdx < MAXASSIGNS {
			assign := &dispatch.Assigns[potentialNewIdx]
			origEmptyState := assign.Cost
			// Record original stations length? We'll rely on AddShip/GenRoute behavior.
			// Attempt insertion into this currently-unused assign
			if assign.AddShip(shipID, ori, des) {
				assign.GenRoute()
				newCost := assign.Cost
				delta := newCost
				if newCost >= 0 && delta < minDelta {
					minDelta = delta
					bestIdx = potentialNewIdx
				}
				// Rollback for now; will commit later if chosen
				assign.RemoveShip(shipID)
				assign.GenRoute()
				// Restore original empty state? GenRoute after removal should restore.
			} else {
				// If AddShip fails on an empty assign, something's wrong; ignore for now.
			}
		}
		// Commit best insertion
		if bestIdx >= 0 {
			target := &dispatch.Assigns[bestIdx]
			// Re-add and finalize route
			success := target.AddShip(shipID, ori, des)
			if success {
				target.GenRoute()
				if bestIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen++
				}
			} else {
				// Should not happen because we tested earlier; fallback to forcing new assign
				fallbackIdx := dispatch.AssignsLen
				if fallbackIdx < MAXASSIGNS {
					dispatch.Assigns[fallbackIdx].AddShip(shipID, ori, des)
					dispatch.Assigns[fallbackIdx].GenRoute()
					dispatch.AssignsLen++
				}
			}
		} else {
			// No feasible existing assign and new assign failed earlier? Force into next available slot.
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				dispatch.Assigns[fallbackIdx].AddShip(shipID, ori, des)
				dispatch.Assigns[fallbackIdx].GenRoute()
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

